// tests/application/use-cases/DefaultSettings.test.ts
import assert from "node:assert/strict";
import test from "node:test";

// src/domain/feeds/FeedTypes.ts
var FEED_TYPES = {
  GENERIC_JSON: "generic_json",
  GITHUB_ADVISORY: "github_advisory",
  GITHUB_REPO: "github_repo",
  NVD: "nvd",
  OSV: "osv"
};
var BUILT_IN_FEEDS = {
  GITHUB_ADVISORY: {
    id: "github-advisories-default",
    legacyCursorKey: "GitHub",
    legacySourceAliases: ["github"],
    name: "GitHub",
    type: FEED_TYPES.GITHUB_ADVISORY
  },
  NVD: {
    id: "nvd-default",
    legacyCursorKey: "NVD",
    legacySourceAliases: [FEED_TYPES.NVD],
    name: "NVD",
    type: FEED_TYPES.NVD
  },
  OSV: {
    id: "osv-default",
    legacySourceAliases: [FEED_TYPES.OSV],
    name: "OSV",
    type: FEED_TYPES.OSV
  }
};

// src/domain/triage/TriageState.ts
var TRIAGE_STATES = [
  "active",
  "investigating",
  "accepted_risk",
  "mitigated",
  "false_positive",
  "suppressed"
];
var CLOSED_TRIAGE_STATES = ["mitigated", "false_positive", "suppressed"];
var TRIAGE_STATE_SET = new Set(TRIAGE_STATES);

// src/application/use-cases/DefaultSettings.ts
var DEFAULT_COLUMN_VISIBILITY = {
  id: true,
  title: true,
  source: true,
  severity: true,
  cvssScore: true,
  publishedAt: true
};
var DEFAULT_FEEDS = [
  {
    id: BUILT_IN_FEEDS.NVD.id,
    name: BUILT_IN_FEEDS.NVD.name,
    type: BUILT_IN_FEEDS.NVD.type,
    enabled: true,
    dateFilterType: "modified"
  },
  {
    id: BUILT_IN_FEEDS.GITHUB_ADVISORY.id,
    name: BUILT_IN_FEEDS.GITHUB_ADVISORY.name,
    type: BUILT_IN_FEEDS.GITHUB_ADVISORY.type,
    enabled: true
  },
  {
    id: BUILT_IN_FEEDS.OSV.id,
    name: BUILT_IN_FEEDS.OSV.name,
    type: BUILT_IN_FEEDS.OSV.type,
    enabled: false,
    cacheTtlMs: 6 * 60 * 60 * 1e3,
    negativeCacheTtlMs: 60 * 60 * 1e3,
    requestTimeoutMs: 15e3,
    maxConcurrentBatches: 4
  }
];
var MAX_OSV_CONCURRENT_BATCHES = 8;
var DEFAULT_CACHE_STORAGE = {
  hardCap: 5e3,
  hydrateMaxItems: 1e3,
  hydratePageSize: 200,
  pruneBatchSize: 250,
  ttlMs: 30 * 24 * 60 * 60 * 1e3
};
var DEFAULT_DAILY_ROLLUP_SETTINGS = {
  folderPath: "VulnDash Briefings",
  severityThreshold: "HIGH",
  excludedTriageStates: [...CLOSED_TRIAGE_STATES],
  includeUnmappedFindings: true,
  autoGenerateOnFirstSyncOfDay: false,
  lastAutoGeneratedOn: ""
};
var DEFAULT_SYNC_CONTROLS = {
  maxPages: 10,
  maxItems: 500,
  retryCount: 3,
  backoffBaseMs: 1e3,
  overlapWindowMs: 18e4,
  bootstrapLookbackMs: 864e5,
  debugHttpMetadata: false
};
var SETTINGS_VERSION = 9;
var DEFAULT_SETTINGS = {
  pollingIntervalMs: 6e4,
  pollOnStartup: true,
  keywordFilters: [],
  manualProductFilters: [],
  sbomFolders: [],
  followedSbomComponentKeys: [],
  disabledSbomComponentKeys: [],
  productFilters: [],
  minSeverity: "MEDIUM",
  minCvssScore: 4,
  nvdApiKey: "",
  githubToken: "",
  systemNotificationsEnabled: true,
  desktopAlertsHighOrCritical: false,
  cacheDurationMs: 6e4,
  maxResults: 200,
  defaultSortOrder: "publishedAt",
  dashboardDateField: "modified",
  colorCodedSeverity: true,
  columnVisibility: DEFAULT_COLUMN_VISIBILITY,
  triageFilter: "all",
  keywordRegexEnabled: false,
  enableNvdFeed: true,
  enableGithubFeed: true,
  dailyRollup: { ...DEFAULT_DAILY_ROLLUP_SETTINGS },
  sboms: [],
  sbomOverrides: {},
  sbomImportMode: "append",
  sbomPath: "",
  syncControls: { ...DEFAULT_SYNC_CONTROLS },
  sourceSyncCursor: {},
  cacheStorage: DEFAULT_CACHE_STORAGE,
  settingsVersion: SETTINGS_VERSION,
  feeds: DEFAULT_FEEDS.map((feed) => ({ ...feed }))
};
var getDefaultOsvFeedConfig = () => {
  const defaultFeed = DEFAULT_FEEDS.find((feed) => feed.type === FEED_TYPES.OSV);
  if (!defaultFeed) {
    throw new Error("Missing default OSV feed configuration.");
  }
  return defaultFeed;
};

// tests/application/use-cases/DefaultSettings.test.ts
test("default settings constants preserve the existing built-in values", () => {
  assert.deepEqual(DEFAULT_COLUMN_VISIBILITY, {
    id: true,
    title: true,
    source: true,
    severity: true,
    cvssScore: true,
    publishedAt: true
  });
  assert.deepEqual(DEFAULT_CACHE_STORAGE, {
    hardCap: 5e3,
    hydrateMaxItems: 1e3,
    hydratePageSize: 200,
    pruneBatchSize: 250,
    ttlMs: 30 * 24 * 60 * 60 * 1e3
  });
  assert.deepEqual(DEFAULT_DAILY_ROLLUP_SETTINGS, {
    folderPath: "VulnDash Briefings",
    severityThreshold: "HIGH",
    excludedTriageStates: [...CLOSED_TRIAGE_STATES],
    includeUnmappedFindings: true,
    autoGenerateOnFirstSyncOfDay: false,
    lastAutoGeneratedOn: ""
  });
  assert.deepEqual(DEFAULT_SYNC_CONTROLS, {
    maxPages: 10,
    maxItems: 500,
    retryCount: 3,
    backoffBaseMs: 1e3,
    overlapWindowMs: 18e4,
    bootstrapLookbackMs: 864e5,
    debugHttpMetadata: false
  });
  assert.equal(MAX_OSV_CONCURRENT_BATCHES, 8);
  assert.equal(SETTINGS_VERSION, 9);
});
test("default feeds remain stable and the OSV helper returns the built-in OSV feed", () => {
  assert.deepEqual(DEFAULT_FEEDS, [
    {
      id: BUILT_IN_FEEDS.NVD.id,
      name: BUILT_IN_FEEDS.NVD.name,
      type: FEED_TYPES.NVD,
      enabled: true,
      dateFilterType: "modified"
    },
    {
      id: BUILT_IN_FEEDS.GITHUB_ADVISORY.id,
      name: BUILT_IN_FEEDS.GITHUB_ADVISORY.name,
      type: FEED_TYPES.GITHUB_ADVISORY,
      enabled: true
    },
    {
      id: BUILT_IN_FEEDS.OSV.id,
      name: BUILT_IN_FEEDS.OSV.name,
      type: FEED_TYPES.OSV,
      enabled: false,
      cacheTtlMs: 216e5,
      negativeCacheTtlMs: 36e5,
      requestTimeoutMs: 15e3,
      maxConcurrentBatches: 4
    }
  ]);
  assert.deepEqual(getDefaultOsvFeedConfig(), DEFAULT_FEEDS[2]);
});
test("default settings still compose the extracted constants without mutating values", () => {
  assert.equal(DEFAULT_SETTINGS.columnVisibility, DEFAULT_COLUMN_VISIBILITY);
  assert.equal(DEFAULT_SETTINGS.cacheStorage, DEFAULT_CACHE_STORAGE);
  assert.deepEqual(DEFAULT_SETTINGS.dailyRollup, DEFAULT_DAILY_ROLLUP_SETTINGS);
  assert.deepEqual(DEFAULT_SETTINGS.syncControls, DEFAULT_SYNC_CONTROLS);
  assert.notEqual(DEFAULT_SETTINGS.dailyRollup, DEFAULT_DAILY_ROLLUP_SETTINGS);
  assert.notEqual(DEFAULT_SETTINGS.syncControls, DEFAULT_SYNC_CONTROLS);
  assert.equal(DEFAULT_SETTINGS.settingsVersion, SETTINGS_VERSION);
  assert.deepEqual(DEFAULT_SETTINGS.feeds, DEFAULT_FEEDS);
  assert.notEqual(DEFAULT_SETTINGS.feeds, DEFAULT_FEEDS);
});
